#!/usr/bin/env node
/**
 * server.js — LRB Dashboard Server
 * Serves web UI, proxies CDP, handles Git commit/push.
 *
 * Ports:
 *   3030  — Dashboard web UI + REST API
 *   9223  — Chromium CDP (started separately)
 */

import http from 'node:http';
import fs from 'node:fs';
import path from 'node:path';
import { spawn, execSync } from 'node:child_process';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_DIR = __dirname;
const DATA_DIR = path.join(REPO_DIR, 'data');
const CDP_PORT = 9223;
const DASHBOARD_PORT = 3030;

// ============================================================
//  Git helpers
// ============================================================

function git(...args) {
  try {
    const output = execSync(`git -C "${REPO_DIR}" ${args.join(' ')}`, {
      encoding: 'utf-8',
      maxBuffer: 10 * 1024 * 1024,
    });
    return { ok: true, output: output.trim() };
  } catch (err) {
    return { ok: false, output: err.stderr?.trim() || err.message };
  }
}

function getGitStatus() {
  const status = git('status', '--porcelain');
  if (!status.ok) return { ok: false, error: status.output };

  const files = status.output
    .split('\n')
    .filter(Boolean)
    .map(line => ({
      status: line.substring(0, 2).trim(),
      file: line.substring(3),
    }));

  // Get size info
  let totalSize = 0;
  for (const f of files) {
    try {
      const fullPath = path.join(REPO_DIR, f.file);
      if (fs.existsSync(fullPath) && fs.statSync(fullPath).isFile()) {
        totalSize += fs.statSync(fullPath).size;
      }
    } catch {}
  }

  return { ok: true, files, totalSize, count: files.length };
}

// ============================================================
//  MIME types
// ============================================================

const MIME = {
  '.html': 'text/html; charset=utf-8',
  '.css': 'text/css; charset=utf-8',
  '.js': 'application/javascript; charset=utf-8',
  '.json': 'application/json',
  '.png': 'image/png',
  '.jpg': 'image/jpeg',
  '.svg': 'image/svg+xml',
  '.ico': 'image/x-icon',
};

// ============================================================
//  Request handler
// ============================================================

async function handleRequest(req, res) {
  const url = new URL(req.url, `http://${req.headers.host}`);
  const pathname = url.pathname;

  // --- CORS ---
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
  if (req.method === 'OPTIONS') {
    res.writeHead(204);
    res.end();
    return;
  }

  try {
    // === API: List tabs ===
    if (pathname === '/api/tabs' && req.method === 'GET') {
      const resp = await fetch(`http://127.0.0.1:${CDP_PORT}/json`);
      const tabs = await resp.json();
      const list = tabs.map(t => ({
        id: t.id,
        title: t.title || '(untitled)',
        url: t.url || '(blank)',
      }));
      writeJSON(res, 200, { ok: true, tabs: list });
      return;
    }

    // === API: Open URL ===
    if (pathname === '/api/open' && req.method === 'POST') {
      const body = await readBody(req);
      const { url: targetUrl } = JSON.parse(body);
      if (!targetUrl) {
        writeJSON(res, 400, { ok: false, error: 'Missing url' });
        return;
      }
      const resp = await fetch(
        `http://127.0.0.1:${CDP_PORT}/json/new?${new URLSearchParams({ url: targetUrl })}`,
        { method: 'PUT' }
      );
      const tab = await resp.json();
      writeJSON(res, 200, { ok: true, tab: { id: tab.id, title: tab.title, url: tab.url } });
      return;
    }

    // === API: Close tab ===
    if (pathname === '/api/close' && req.method === 'POST') {
      const body = await readBody(req);
      const { id: tabId } = JSON.parse(body);
      if (!tabId) {
        writeJSON(res, 400, { ok: false, error: 'Missing id' });
        return;
      }
      await fetch(`http://127.0.0.1:${CDP_PORT}/json/close/${tabId}`, { method: 'GET' });
      writeJSON(res, 200, { ok: true });
      return;
    }

    // === API: Git status ===
    if (pathname === '/api/git/status' && req.method === 'GET') {
      const status = getGitStatus();
      const log = git('log', '--oneline', '-10');
      writeJSON(res, 200, {
        ok: true,
        status,
        recentCommits: log.ok ? log.output.split('\n').filter(Boolean) : [],
      });
      return;
    }

    // === API: Git commit + push ===
    if (pathname === '/api/git/commit' && req.method === 'POST') {
      const body = await readBody(req);
      const { message } = JSON.parse(body);
      const msg = message || `LRB auto-save ${new Date().toISOString()}`;

      // Stage all
      const addResult = git('add', '-A');
      if (!addResult.ok) {
        writeJSON(res, 500, { ok: false, error: `git add failed: ${addResult.output}` });
        return;
      }

      // Commit
      const commitResult = git('commit', '-m', `"${msg.replace(/"/g, '\\"')}"`);
      if (!commitResult.ok) {
        writeJSON(res, 200, { ok: true, note: 'Nothing to commit' });
        return;
      }

      // Push
      const pushResult = git('push', 'origin', 'main');
      if (!pushResult.ok) {
        writeJSON(res, 200, { ok: true, note: 'Committed but push failed', error: pushResult.output });
        return;
      }

      writeJSON(res, 200, { ok: true, commit: commitResult.output, push: 'Pushed to origin' });
      return;
    }

    // === API: Screenshot ===
    if (pathname === '/api/screenshot' && req.method === 'GET') {
      const tabId = url.searchParams.get('id');
      const cdpUrl = tabId
        ? `http://127.0.0.1:${CDP_PORT}/json/activate/${tabId}`
        : `http://127.0.0.1:${CDP_PORT}/json/version`;

      if (tabId) {
        await fetch(cdpUrl, { method: 'GET' });
      }

      // Use websocket + CDP for screenshot
      const tabList = await (await fetch(`http://127.0.0.1:${CDP_PORT}/json`)).json();
      const target = tabId ? tabList.find(t => t.id === tabId) : tabList[0];
      if (!target) {
        writeJSON(res, 404, { ok: false, error: 'No tab found' });
        return;
      }

      const wsUrl = target.webSocketDebuggerUrl;
      const CDP = (await import('chrome-remote-interface')).default;
      const client = await CDP({ host: '127.0.0.1', port: CDP_PORT, target: tabId || undefined });
      try {
        const { Page } = client;
        await Page.enable();
        const { data } = await Page.captureScreenshot({ format: 'png', fromSurface: true });
        const img = Buffer.from(data, 'base64');
        res.writeHead(200, {
          'Content-Type': 'image/png',
          'Content-Length': img.length,
        });
        res.end(img);
      } finally {
        client.close();
      }
      return;
    }

    // === Serve dashboard UI ===
    if (pathname === '/' || pathname === '/dashboard') {
      const html = fs.readFileSync(path.join(REPO_DIR, 'dashboard', 'index.html'), 'utf-8');
      res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
      res.end(html);
      return;
    }

    // === Serve static files ===
    const publicDir = path.join(REPO_DIR, 'dashboard');
    let filePath = path.join(publicDir, pathname === '/favicon.ico' ? 'favicon.ico' : pathname);

    if (fs.existsSync(filePath) && fs.statSync(filePath).isFile()) {
      const ext = path.extname(filePath);
      res.writeHead(200, { 'Content-Type': MIME[ext] || 'application/octet-stream' });
      res.end(fs.readFileSync(filePath));
      return;
    }

    // 404
    writeJSON(res, 404, { ok: false, error: 'Not found' });
  } catch (err) {
    writeJSON(res, 500, { ok: false, error: err.message });
  }
}

// ============================================================
//  Utilities
// ============================================================

function writeJSON(res, status, data) {
  const body = JSON.stringify(data, null, 2);
  res.writeHead(status, { 'Content-Type': 'application/json' });
  res.end(body);
}

function readBody(req) {
  return new Promise((resolve, reject) => {
    const chunks = [];
    req.on('data', c => chunks.push(c));
    req.on('end', () => resolve(Buffer.concat(chunks).toString()));
    req.on('error', reject);
  });
}

// ============================================================
//  Start
// ============================================================

const server = http.createServer(handleRequest);
server.listen(DASHBOARD_PORT, '0.0.0.0', () => {
  console.log(`📊 LRB Dashboard: http://0.0.0.0:${DASHBOARD_PORT}`);
  try {
    const ts = execSync('tailscale ip -4 2>/dev/null', { encoding: 'utf-8' }).trim();
    if (ts) {
      console.log(`🌐 Via Tailscale: http://${ts}:${DASHBOARD_PORT}`);
    }
  } catch {}
});

