      await fetch(`http://127.0.0.1:${CDP_PORT}/json/close/${tabId}`, { method: 'GET' });
      writeJSON(res, 200, { ok: true });
      return;
    }

    // === API: Git status ===
    if (pathname === '/api/git/status' && req.method === 'GET') {
      const status = getGitStatus();
      const log = git('log', '--oneline', '-10');
      writeJSON(res, 200, {
        ok: true,
        status,
        recentCommits: log.ok ? log.output.split('\n').filter(Boolean) : [],
      });
      return;
    }

    // === API: Git commit + push ===
    if (pathname === '/api/git/commit' && req.method === 'POST') {
      const body = await readBody(req);
      const { message } = JSON.parse(body);
      const msg = message || `LRB auto-save ${new Date().toISOString()}`;

      // Stage all
      const addResult = git('add', '-A');
      if (!addResult.ok) {
        writeJSON(res, 500, { ok: false, error: `git add failed: ${addResult.output}` });
        return;
      }

      // Commit
      const commitResult = git('commit', '-m', `"${msg.replace(/"/g, '\\"')}"`);
      if (!commitResult.ok) {
        writeJSON(res, 200, { ok: true, note: 'Nothing to commit' });
        return;
      }

      // Push
      const pushResult = git('push', 'origin', 'main');
      if (!pushResult.ok) {
        writeJSON(res, 200, { ok: true, note: 'Committed but push failed', error: pushResult.output });
        return;
      }

      writeJSON(res, 200, { ok: true, commit: commitResult.output, push: 'Pushed to origin' });
      return;
    }

    // === API: Screenshot ===
    if (pathname === '/api/screenshot' && req.method === 'GET') {
      const tabId = url.searchParams.get('id');
      const cdpUrl = tabId
        ? `http://127.0.0.1:${CDP_PORT}/json/activate/${tabId}`
        : `http://127.0.0.1:${CDP_PORT}/json/version`;

      if (tabId) {
        await fetch(cdpUrl, { method: 'GET' });
      }

      // Use websocket + CDP for screenshot
      const tabList = await (await fetch(`http://127.0.0.1:${CDP_PORT}/json`)).json();
      const target = tabId ? tabList.find(t => t.id === tabId) : tabList[0];
      if (!target) {
        writeJSON(res, 404, { ok: false, error: 'No tab found' });
        return;
      }

      const wsUrl = target.webSocketDebuggerUrl;
      const CDP = (await import('chrome-remote-interface')).default;
      const client = await CDP({ host: '127.0.0.1', port: CDP_PORT, target: tabId || undefined });
      try {
        const { Page } = client;
        await Page.enable();
        const { data } = await Page.captureScreenshot({ format: 'png', fromSurface: true });
        const img = Buffer.from(data, 'base64');
        res.writeHead(200, {
          'Content-Type': 'image/png',
          'Content-Length': img.length,
        });
        res.end(img);
      } finally {
        client.close();
      }
      return;
    }

    // === Serve dashboard UI ===
    if (pathname === '/' || pathname === '/dashboard') {
      const html = fs.readFileSync(path.join(REPO_DIR, 'dashboard', 'index.html'), 'utf-8');
      res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
      res.end(html);
      return;
    }

    // === Serve static files ===
    const publicDir = path.join(REPO_DIR, 'dashboard');
    let filePath = path.join(publicDir, pathname === '/favicon.ico' ? 'favicon.ico' : pathname);

    if (fs.existsSync(filePath) && fs.statSync(filePath).isFile()) {
      const ext = path.extname(filePath);
      res.writeHead(200, { 'Content-Type': MIME[ext] || 'application/octet-stream' });
      res.end(fs.readFileSync(filePath));
      return;
    }

    // 404
    writeJSON(res, 404, { ok: false, error: 'Not found' });
  } catch (err) {
    writeJSON(res, 500, { ok: false, error: err.message });
  }
}

// ============================================================
//  Utilities
// ============================================================

function writeJSON(res, status, data) {
  const body = JSON.stringify(data, null, 2);
  res.writeHead(status, { 'Content-Type': 'application/json' });
  res.end(body);
}

function readBody(req) {
  return new Promise((resolve, reject) => {
    const chunks = [];
    req.on('data', c => chunks.push(c));
    req.on('end', () => resolve(Buffer.concat(chunks).toString()));
    req.on('error', reject);
  });
}

// ============================================================
//  Start
// ============================================================

const server = http.createServer(handleRequest);
server.listen(DASHBOARD_PORT, '0.0.0.0', () => {
  console.log(`📊 LRB Dashboard: http://0.0.0.0:${DASHBOARD_PORT}`);
  try {
    const ts = execSync('tailscale ip -4 2>/dev/null', { encoding: 'utf-8' }).trim();
    if (ts) {
      console.log(`🌐 Via Tailscale: http://${ts}:${DASHBOARD_PORT}`);
    }
  } catch {}
});
