const API_BASE = 'https://api.football-data.org/v4';

async function fetchFromAPI(apiKey, endpoint) {
  const resp = await fetch(`${API_BASE}${endpoint}`, {
    headers: { 'X-Auth-Token': apiKey }
  });
  if (!resp.ok) {
    if (resp.status === 429) throw new Error('Rate limited. Wait a moment.');
    if (resp.status === 403) throw new Error('Invalid API key.');
    throw new Error(`API error: ${resp.status}`);
  }
  return resp.json();
}

function getDemoMatches(teamId) {
  const demo = DEMO_DATA[teamId];
  if (!demo) return [];

  const matches = [];
  for (let i = 0; i < demo.results.length; i += 2) {
    const homeScore = i % 4 === 0 ? demo.results[i] : demo.results[i+1];
    const awayScore = i % 4 === 0 ? demo.results[i+1] : demo.results[i];
    const oppIdx = Math.floor(i / 2) % demo.opp.length;

    matches.push({
      homeTeamId: teamId,
      awayTeamId: 0,
      homeScore,
      awayScore,
      opponent: demo.opp[oppIdx],
      date: new Date(Date.now() - (demo.results.length - i) * 3 * 86400000).toISOString(),
    });
  }
  return matches;
}

async function loadPremierLeague(apiKey) {
  const content = document.getElementById('content');

  if (apiKey) {
    content.innerHTML = `<div class="loading-state"><div class="spinner"></div><p>Fetching Premier League data...</p></div>`;

    try {
      // Get standings
      const standings = await fetchFromAPI(apiKey, '/competitions/PL/standings');

      // Get recent matches for each team
      const matches = await fetchFromAPI(apiKey, '/competitions/PL/matches?limit=100');

      processAndRender(standings, matches, apiKey);
    } catch (err) {
      content.innerHTML = `<div class="error-state">
        <p>❌ ${err.message}</p>
        <p style="margin-top:8px;font-size:0.8rem;color:var(--text2)">Falling back to demo data...</p>
      </div>`;
      setTimeout(() => useDemoData(), 1500);
    }
  } else {
    useDemoData();
  }
}

function useDemoData() {
  const content = document.getElementById('content');
  content.innerHTML = `<div class="loading-state"><div class="spinner"></div><p>Loading demo data...</p></div>`;

  setTimeout(() => {
    processAndRenderDemo();
  }, 500);
}

// ============================================================
//  RENDERING
// ============================================================

function processAndRenderDemo() {
  const allAnalyses = [];

  for (const team of PREM_TEAMS) {
    const matches = getDemoMatches(team.id);
    const analysis = analyzeTeam(team.id, team.name, matches);

    allAnalyses.push({
      team,
      matches,
      ...analysis,
    });
  }

  renderAll(allAnalyses, null);
}

function processAndRender(standingsData, matchesData, apiKey) {
  // Extract standings
  const standings = standingsData.standings?.[0]?.table || [];
  const standingsMap = {};
  for (const entry of standings) {
    standingsMap[entry.team.id] = entry.position;
  }

  // Extract matches per team
  const allMatches = matchesData.matches || [];
  const teamMatches = {};

  for (const team of PREM_TEAMS) {
    teamMatches[team.id] = [];
  }

  for (const match of allMatches) {
    if (match.status !== 'FINISHED') continue;

    const homeId = match.homeTeam.id;
    const awayId = match.awayTeam.id;
    const homeScore = match.score?.fullTime?.home ?? 0;
    const awayScore = match.score?.fullTime?.away ?? 0;

    if (teamMatches[homeId]) {
      teamMatches[homeId].push({
        homeTeamId: homeId,
        awayTeamId: awayId,
        homeScore,
        awayScore,
        opponent: match.awayTeam.shortName || match.awayTeam.name,
        date: match.utcDate,
      });
    }
    if (teamMatches[awayId]) {
      teamMatches[awayId].push({
        homeTeamId: homeId,
        awayTeamId: awayId,
        homeScore,
        awayScore,
        opponent: match.homeTeam.shortName || match.homeTeam.name,
        date: match.utcDate,
      });
    }
  }

  // Sort each team's matches by date
  for (const id in teamMatches) {
    teamMatches[id].sort((a, b) => new Date(a.date) - new Date(b.date));
  }

  const allAnalyses = [];
  for (const team of PREM_TEAMS) {
    const matches = teamMatches[team.id] || [];
    const position = standingsMap[team.id] || '-';
    const analysis = analyzeTeam(team.id, team.name, matches);

    allAnalyses.push({
      team: { ...team, position },
      matches,
      ...analysis,
    });
  }

  renderAll(allAnalyses, apiKey);
  document.getElementById('btnRefresh').style.display = 'inline-block';
}

function renderAll(analyses, apiKey) {
  const content = document.getElementById('content');

  let totalPatterns = 0;
  let totalPredictions = 0;
  let totalMatches = 0;

  for (const a of analyses) {
    totalPatterns += a.patterns.length;
    totalPredictions += a.predictions.length;
    totalMatches += a.matches.length;
  }

  document.getElementById('statsGrid').style.display = 'grid';
  document.getElementById('statTeams').textContent = analyses.length;
  document.getElementById('statPatterns').textContent = totalPatterns;
  document.getElementById('statPredictions').textContent = totalPredictions;
  document.getElementById('statMatches').textContent = totalMatches;

  let html = '';

  for (const a of analyses) {
    const last5 = a.results.slice(-5);

    html += `<div class="team-card">
      <div class="team-header">
        <span class="team-name">${a.team.name}</span>
        <span class="team-position">#${a.team.position || '-'}</span>
      </div>
      <div class="match-history">`;

    for (const r of a.results.slice(-10)) {
      const cls = r.isWin ? 'match-win' : r.isDraw ? 'match-draw' : 'match-loss';
      html += `<span class="match-pill ${cls}">${r.scored}-${r.conceded}</span>`;
    }

    html += `</div>`;

    // Predictions
    if (a.predictions.length > 0) {
      html += `<div class="pattern-section">
        <div class="pattern-title">🔮 Predictions for Next Match</div>`;
      for (const p of a.predictions.slice(0, 2)) {
        const confColor = p.confidence >= 75 ? 'var(--accent2)' : p.confidence >= 60 ? 'var(--gold)' : 'var(--text2)';
        html += `<div class="prediction-box">
          <div class="pred-text">${p.type}</div>
          <div class="pred-sub" style="font-size:0.75rem;color:var(--text2);margin-top:4px">${p.reason}</div>
          <div style="margin-top:6px;font-size:0.75rem;color:${confColor};font-weight:600">${p.confidence}% confidence</div>
        </div>`;
      }
      html += `</div>`;
    }

    // Pattern history
    if (a.patterns.length > 0) {
      html += `<div class="pattern-section">
        <div class="pattern-title">📊 Analyzed Patterns (Last ${a.patterns.length})</div>`;
      for (const p of a.patterns.slice(-5).reverse()) {
        const resultColor = p.triggered 
          ? (p.result.includes('PASS') ? 'var(--accent2)' : 'var(--accent)')
          : 'var(--gold)';
        html += `<div class="pattern-rule">
          <span class="if">IF</span> ${p.condition}
          <span class="arrow">→</span>
          <span class="then">THEN</span> next game ${p.prediction ? '>2.5 goals' : '<2.5 goals'}
          <span style="float:right;color:${resultColor};font-weight:600">${p.result}</span>
        </div>`;
      }
      html += `</div>`;
    }

    // Recent goals trends
    const recentG = a.goalsScored.slice(-5);
    html += `<div class="pattern-section" style="margin-top:8px">
      <div class="pattern-title">📈 Goal Trend (Last 5)</div>
      <div style="display:flex;gap:4px;align-items:center;height:40px">`;

    for (const g of recentG) {
      const h = Math.min(g * 12, 36);
      const color = g >= 3 ? 'var(--accent2)' : g >= 2 ? 'var(--gold)' : g >= 1 ? 'var(--accent)' : 'var(--text2)';
      html += `<div style="flex:1;height:${h}px;background:${color};border-radius:4px 4px 0 0;align-self:flex-end;text-align:center;font-size:0.7rem;padding-top:${h > 20 ? 2 : 8}px;min-height:12px">${g}</div>`;
    }

    html += `</div></div>`;

    html += `</div>`;
  }

  content.innerHTML = `<div class="team-grid">${html}</div>`;
}

// ============================================================
//  INIT
// ============================================================

document.getElementById('btnLoad').addEventListener('click', () => {
  const apiKey = document.getElementById('apiKey').value.trim();
  loadPremierLeague(apiKey);
});

document.getElementById('btnRefresh').addEventListener('click', () => {
  const apiKey = document.getElementById('apiKey').value.trim();
  loadPremierLeague(apiKey);
});

document.getElementById('btnHelp').addEventListener('click', () => {
  document.getElementById('helpModal').classList.add('active');
});

document.getElementById('btnCloseHelp').addEventListener('click', () => {
  document.getElementById('helpModal').classList.remove('active');
});

document.getElementById('helpModal').addEventListener('click', (e) => {
  if (e.target === e.currentTarget) {
    document.getElementById('helpModal').classList.remove('active');
  }
});

// Load with demo data on first visit
const savedKey = localStorage.getItem('yg2-api-key');
if (savedKey) {
  document.getElementById('apiKey').value = savedKey;
}

useDemoData();

// Save key on use
document.getElementById('apiKey').addEventListener('input', () => {
  const key = document.getElementById('apiKey').value.trim();
  if (key) localStorage.setItem('yg2-api-key', key);
});
</script>
</body>
</html>
