// ============================================================
//  MATCH GENERATOR
//  Generates realistic Premier League results 2006-2026
// ============================================================

const SEASONS = Object.keys(SEASON_TEAMS);
let matchCache = {};

function generateMatches(teamName) {
  const cacheKey = teamName;
  if (matchCache[cacheKey]) return matchCache[cacheKey];

  const matches = [];
  let matchId = 0;

  for (const season of SEASONS) {
    const teamsInSeason = SEASON_TEAMS[season];
    if (!teamsInSeason.includes(teamName)) continue;

    const strength = getStrength(teamName, season);
    const opponents = teamsInSeason.filter(t => t !== teamName);
    // Shuffle opponents deterministically for variety
    const shuffled = [...opponents].sort((a, b) => {
      const ha = a.charCodeAt(0) + a.charCodeAt(a.length-1);
      const hb = b.charCodeAt(0) + b.charCodeAt(b.length-1);
      return ha - hb;
    });

    // Each team plays 38 matches (home and away against 19 others)
    // Half home, half away
    const numMatches = Math.min(38, shuffled.length * 2);
    for (let i = 0; i < numMatches; i++) {
      const opp = shuffled[i % shuffled.length];
      const oppStrength = getStrength(opp, season);
      const isHome = i < shuffled.length;

      // Generate realistic score based on strengths
      const strengthDiff = isHome ? (strength - oppStrength + 8) : (strength - oppStrength - 3);
      const homeExp = Math.max(0.2, Math.min(4.5, 1.2 + strengthDiff * 0.04 + Math.random() * 0.5));
      const awayExp = Math.max(0.1, Math.min(4.0, 0.8 - strengthDiff * 0.03 + Math.random() * 0.4));

      let homeGoals, awayGoals;
      if (isHome) {
        homeGoals = poissonSample(homeExp);
        awayGoals = poissonSample(awayExp);
      } else {
        homeGoals = poissonSample(awayExp + 0.3);
        awayGoals = poissonSample(homeExp - 0.2);
      }

      // Clamp to realistic values
      homeGoals = Math.max(0, Math.min(8, homeGoals));
      awayGoals = Math.max(0, Math.min(8, awayGoals));

      const month = 8 + Math.floor((i / numMatches) * 9);
      const day = 1 + Math.floor(Math.random() * 28);
      const dateStr = `${season.substring(0,4)}-${String(month).padStart(2,'0')}-${String(day).padStart(2,'0')}`;

      matches.push({
        id: ++matchId,
        season,
        date: dateStr,
        home: isHome ? teamName : opp,
        away: isHome ? opp : teamName,
        homeGoals: isHome ? homeGoals : awayGoals,
        awayGoals: isHome ? awayGoals : homeGoals,
        isHome,
      });
    }
  }

  // Sort by date
  matches.sort((a, b) => a.date.localeCompare(b.date));

  matchCache[cacheKey] = matches;
  return matches;
}

function poissonSample(lambda) {
  const L = Math.exp(-lambda);
  let k = 0;
  let p = 1;
  do {
    k++;
    p *= Math.random();
  } while (p > L);
  return k - 1;
}

