function describeConfig(config) {
  if (config.resultType) {
    return `${config.consecutive} consecutive ${matchLabel(config.resultType)} → analyze next match`;
  }
  return `${metricLabel(config.metric)} ${compLabel(config.compare)} ${config.value} in ${config.consecutive} consecutive → analyze next match`;
}

function metricLabel(m) {
  const labels = { scored: 'Goals Scored', conceded: 'Goals Conceded', total: 'Total Goals', margin: 'Goal Margin', result: 'Result' };
  return labels[m] || m;
}
function compLabel(c) {
  const labels = { lt: '<', lte: '≤', eq: '=', gte: '≥', gt: '>' };
  return labels[c] || c;
}
function matchLabel(r) {
  const labels = { win: 'wins', draw: 'draws', loss: 'losses', not_loss: 'not-lost', not_win: 'not-won' };
  return labels[r] || r;
}

function getBuilderConfig() {
