  @media (max-width: 800px) { .grid { grid-template-columns: 1fr; } }
  .card {
    background: var(--surface);
    border: 1px solid #2a2a4a;
    border-radius: 12px;
    padding: 16px;
    margin-bottom: 16px;
  }
  .card h2 {
    font-size: 1rem;
    color: var(--accent);
    margin-bottom: 12px;
    display: flex;
    justify-content: space-between;
