<div class="container">
  <header>
    <h1>⚽ YouGamble2</h1>
    <p>Premier League Pattern Analyzer — Custom IF→THEN Logic Engine</p>
    <div class="subtitle">2006–2026 · 20 seasons · 7,600+ matches</div>
  </header>

  <!-- Controls -->
  <div class="controls">
    <div class="control-card">
      <h3>① Select Team</h3>
      <select id="teamSelect"><option value="">— Choose a team —</option></select>
      <div style="margin-top:4px;font-size:0.75rem;color:var(--text2)">
        Data range: <span id="dataRange">2006–2026 (20 seasons)</span>
      </div>
    </div>
    <div class="control-card">
      <h3>② Select Season Range</h3>
      <div class="control-row">
        <label>From:</label>
        <select id="seasonFrom"></select>
        <label>To:</label>
        <select id="seasonTo"></select>
      </div>
      <button class="btn-primary btn-sm" id="btnLoadTeam">🔍 Analyze Team</button>
    </div>
  </div>

  <!-- Tabs -->
  <div class="tabs">
    <div class="tab-btn active" data-tab="patterns">📊 Pattern Analysis</div>
    <div class="tab-btn" data-tab="builder">🔧 Pattern Builder</div>
    <div class="tab-btn" data-tab="saved">💾 Saved Patterns</div>
    <div class="tab-btn" data-tab="matches">📅 Match History</div>
  </div>

  <!-- Saved patterns bar -->
  <div id="savedPatternsBar"></div>

  <!-- Tab: Pattern Analysis -->
  <div class="tab-content active" id="tab-patterns">
    <div id="patternResults">
      <div class="empty-state">
        <div class="big">👆</div>
        <p>Select a team and click <strong>Analyze Team</strong> to start.</p>
        <p style="margin-top:4px;font-size:0.8rem;color:var(--text2)">
          Then use the built-in rules or create your own in <strong>Pattern Builder</strong>.
        </p>
      </div>
    </div>
  </div>

  <!-- Tab: Pattern Builder -->
  <div class="tab-content" id="tab-builder">
    <div class="help-note">
      <strong>🛠 Custom Pattern Builder</strong> — Define your own IF→THEN rules.<br>
      Example: <em>"If Arsenal scored <strong>&lt; 1 goal</strong> in <strong>3 consecutive</strong> games, what happened in the 4th game?"</em>
    </div>

    <div class="controls" style="grid-template-columns:1fr;">
      <div class="control-card">
        <h3>Condition (IF)</h3>
        <div class="control-row">
          <select id="builderMetric">
            <option value="scored">Goals Scored</option>
            <option value="conceded">Goals Conceded</option>
            <option value="total">Total Goals (scored+conceded)</option>
            <option value="margin">Goal Margin</option>
            <option value="result">Match Result</option>
          </select>
        </div>
        <div class="control-row" id="builderCompareRow">
          <select id="builderCompare">
            <option value="lt">&lt; (less than)</option>
            <option value="lte">≤ (less or equal)</option>
            <option value="eq">= (equal to)</option>
            <option value="gte">≥ (greater or equal)</option>
            <option value="gt">&gt; (greater than)</option>
          </select>
          <label>Value:</label>
          <input type="number" id="builderValue" value="1" min="0" max="20" />
        </div>
        <div id="builderResultRow" class="control-row" style="display:none;">
          <select id="builderResult">
            <option value="win">Won</option>
            <option value="draw">Drew</option>
            <option value="loss">Lost</option>
            <option value="not_loss">Didn't Lose (Won/Drew)</option>
            <option value="not_win">Didn't Win (Drew/Lost)</option>
          </select>
        </div>
        <div class="control-row">
          <label>for <strong>consecutive</strong> matches:</label>
          <input type="number" id="builderConsecutive" value="3" min="1" max="20" style="width:60px;margin-bottom:0;" />
        </div>
      </div>
    </div>

    <div class="controls" style="grid-template-columns:1fr;">
      <div class="control-card">
        <h3>Analysis (THEN)</h3>
        <div style="font-size:0.8rem;color:var(--text2);margin-bottom:8px;">
          Analyze what happens in the <strong>next match</strong> after the condition is met.
        </div>
        <div class="control-row">
          <label>Analyze:</label>
          <select id="builderAnalysis">
            <option value="goals_scored">Goals scored</option>
            <option value="goals_conceded">Goals conceded</option>
            <option value="total_goals">Total goals (over/under)</option>
            <option value="result">Match result</option>
            <option value="both_scored">Both teams scored?</option>
          </select>
        </div>
      </div>
    </div>

    <div style="display:flex;gap:8px;margin-bottom:16px;">
      <button class="btn-purple" id="btnRunCustomPattern">🔍 Analyze Custom Pattern</button>
      <button class="btn-secondary" id="btnSaveCustomPattern">💾 Save Pattern</button>
    </div>

    <div id="customPatternResults"></div>
  </div>

  <!-- Tab: Saved Patterns -->
  <div class="tab-content" id="tab-saved">
    <div class="help-note">
      <strong>💾 Saved Patterns</strong> — Your reusable custom patterns. Click to run them on the current team.
    </div>
    <div id="savedPatternList">
      <div class="empty-state">
        <div class="big">📋</div>
        <p>No saved patterns yet.</p>
        <p style="font-size:0.8rem;color:var(--text2);margin-top:4px">
          Go to <strong>Pattern Builder</strong> to create and save custom rules.
        </p>
      </div>
    </div>
  </div>

  <!-- Tab: Match History -->
  <div class="tab-content" id="tab-matches">
    <div class="controls" style="grid-template-columns:1fr 1fr;">
      <div class="control-card">
        <h3>📅 Matches</h3>
        <div class="control-row">
          <label>Show:</label>
          <select id="matchFilter">
            <option value="all">All matches</option>
            <option value="home">Home only</option>
            <option value="away">Away only</option>
            <option value="wins">Wins only</option>
            <option value="losses">Losses only</option>
            <option value="draws">Draws only</option>
            <option value="over25">Over 2.5 goals</option>
            <option value="under25">Under 2.5 goals</option>
          </select>
        </div>
      </div>
      <div class="control-card" style="display:flex;align-items:center;justify-content:center;">
        <div style="text-align:center">
          <div style="font-size:2rem;font-weight:800;color:var(--gold)" id="totalMatchesCount">0</div>
          <div style="color:var(--text2);font-size:0.75rem">Total Matches</div>
        </div>
      </div>
    </div>
    <div id="matchHistoryList">
      <div class="empty-state">
        <div class="big">👆</div>
        <p>Select a team to see match history.</p>
      </div>
    </div>
  </div>

  <div class="footer">
    YouGamble2 — Premier League Pattern Analyzer. Data from 2006–2026 (20 seasons). Not financial advice.
  </div>
</div>

<div class="toast" id="toast"></div>

<script>
// ============================================================
//  YOUGAMBLE2 — PREMIER LEAGUE PATTERN ANALYZER
//  Data: 2006/07 – 2025/26 (20 seasons, 7,600+ matches)
// ============================================================

const API_KEY = '***';
const API_BASE = 'https://api.football-data.org/v4';

// ============================================================
//  TEAM DATABASE
