// ============================================================
//  MATCH GENERATOR
//  Generates realistic Premier League results 2006-2026
// ============================================================

const SEASONS = Object.keys(SEASON_TEAMS);
let matchCache = {};

function generateMatches(teamName) {
  const cacheKey = teamName;
  if (matchCache[cacheKey]) return matchCache[cacheKey];

  const matches = [];
  let matchId = 0;

  for (const season of SEASONS) {
    const teamsInSeason = SEASON_TEAMS[season];
    if (!teamsInSeason.includes(teamName)) continue;

    const strength = getStrength(teamName, season);
    const opponents = teamsInSeason.filter(t => t !== teamName);
    // Shuffle opponents deterministically for variety
    const shuffled = [...opponents].sort((a, b) => {
      const ha = a.charCodeAt(0) + a.charCodeAt(a.length-1);
      const hb = b.charCodeAt(0) + b.charCodeAt(b.length-1);
      return ha - hb;
    });

    // Each team plays 38 matches (home and away against 19 others)
    // Half home, half away
    const numMatches = Math.min(38, shuffled.length * 2);
    for (let i = 0; i < numMatches; i++) {
      const opp = shuffled[i % shuffled.length];
      const oppStrength = getStrength(opp, season);
      const isHome = i < shuffled.length;

      // Generate realistic score based on strengths
      const strengthDiff = isHome ? (strength - oppStrength + 8) : (strength - oppStrength - 3);
      const homeExp = Math.max(0.2, Math.min(4.5, 1.2 + strengthDiff * 0.04 + Math.random() * 0.5));
      const awayExp = Math.max(0.1, Math.min(4.0, 0.8 - strengthDiff * 0.03 + Math.random() * 0.4));

      let homeGoals, awayGoals;
      if (isHome) {
        homeGoals = poissonSample(homeExp);
        awayGoals = poissonSample(awayExp);
      } else {
        homeGoals = poissonSample(awayExp + 0.3);
        awayGoals = poissonSample(homeExp - 0.2);
      }

      // Clamp to realistic values
      homeGoals = Math.max(0, Math.min(8, homeGoals));
      awayGoals = Math.max(0, Math.min(8, awayGoals));

      const month = 8 + Math.floor((i / numMatches) * 9);
      const day = 1 + Math.floor(Math.random() * 28);
      const dateStr = `${season.substring(0,4)}-${String(month).padStart(2,'0')}-${String(day).padStart(2,'0')}`;

      matches.push({
        id: ++matchId,
        season,
        date: dateStr,
        home: isHome ? teamName : opp,
        away: isHome ? opp : teamName,
        homeGoals: isHome ? homeGoals : awayGoals,
        awayGoals: isHome ? awayGoals : homeGoals,
        isHome,
      });
    }
  }

  // Sort by date
  matches.sort((a, b) => a.date.localeCompare(b.date));

  matchCache[cacheKey] = matches;
  return matches;
}

function poissonSample(lambda) {
  const L = Math.exp(-lambda);
  let k = 0;
  let p = 1;
  do {
    k++;
    p *= Math.random();
  } while (p > L);
  return k - 1;
}

// ============================================================
//  PATTERN ENGINE
// ============================================================

function analyzePattern(matches, teamName, config) {
  // config: { metric, compare, value, consecutive, resultType, analysis }
  const metric = config.metric || 'scored';
  const compare = config.compare || 'lt';
  const value = config.value ?? 1;
  const consecutive = config.consecutive || 3;
  const resultCondition = config.resultType || null;
  const analysis = config.analysis || 'goals_scored';

  // Extract relevant value from match for the team
  function getMetricValue(match) {
    const isHome = match.home === teamName;
    switch (metric) {
      case 'scored': return isHome ? match.homeGoals : match.awayGoals;
      case 'conceded': return isHome ? match.awayGoals : match.homeGoals;
      case 'total': return match.homeGoals + match.awayGoals;
      case 'margin': {
        const for_g = isHome ? match.homeGoals : match.awayGoals;
        const against = isHome ? match.awayGoals : match.homeGoals;
        return for_g - against;
      }
      default: return isHome ? match.homeGoals : match.awayGoals;
    }
  }

  function getResult(match) {
    const isHome = match.home === teamName;
    if (isHome && match.homeGoals > match.awayGoals) return 'win';
    if (!isHome && match.awayGoals > match.homeGoals) return 'win';
    if (match.homeGoals === match.awayGoals) return 'draw';
    return 'loss';
  }

  function compareValues(a, b, op) {
    switch (op) {
      case 'lt': return a < b;
      case 'lte': return a <= b;
      case 'eq': return a === b;
      case 'gte': return a >= b;
      case 'gt': return a > b;
      default: return a < b;
    }
  }

  const occurrences = [];
  const analyses = [];

  for (let i = 0; i <= matches.length - consecutive - 1; i++) {
    const streakMatches = matches.slice(i, i + consecutive);
    const nextMatch = matches[i + consecutive];

    // Check if all streak matches meet the condition
    let conditionMet = true;
    for (const m of streakMatches) {
      const val = getMetricValue(m);
      const res = getResult(m);

      // Check metric condition
      if (resultCondition) {
        // Using result condition
        let resOk = false;
        switch (resultCondition) {
          case 'win': resOk = res === 'win'; break;
          case 'draw': resOk = res === 'draw'; break;
          case 'loss': resOk = res === 'loss'; break;
          case 'not_loss': resOk = res !== 'loss'; break;
          case 'not_win': resOk = res !== 'win'; break;
          default: resOk = true;
        }
        if (!resOk) { conditionMet = false; break; }
      } else {
        // Using numeric condition
        if (!compareValues(val, value, compare)) { conditionMet = false; break; }
      }
    }

    if (conditionMet) {
      occurrences.push({
        startIdx: i,
        endIdx: i + consecutive - 1,
        matches: streakMatches,
        nextMatch,
      });

      // Analyze next match
      const nextVal = getMetricValue(nextMatch);
      const nextRes = getResult(nextMatch);
      const bothScored = nextMatch.homeGoals > 0 && nextMatch.awayGoals > 0;

      analyses.push({
        nextGoalsScored: nextMatch.home === teamName ? nextMatch.homeGoals : nextMatch.awayGoals,
        nextGoalsConceded: nextMatch.home === teamName ? nextMatch.awayGoals : nextMatch.homeGoals,
        nextResult: nextRes,
        bothTeamsScored: bothScored,
        totalGoals: nextMatch.homeGoals + nextMatch.awayGoals,
        match: nextMatch,
      });
    }
  }

  // Compute statistics
  if (analyses.length === 0) {
    return { occurrences: 0, analyses: [], stats: null };
  }

  const stats = {};
  const goalsScoredList = analyses.map(a => a.nextGoalsScored);
  const goalsConcededList = analyses.map(a => a.nextGoalsConceded);
  const totalGoalsList = analyses.map(a => a.totalGoals);
  const resultsList = analyses.map(a => a.nextResult);
  const bothScoredList = analyses.map(a => a.bothTeamsScored);

  const avg = arr => arr.reduce((s, v) => s + v, 0) / arr.length;
  const median = arr => { const s = [...arr].sort((a,b) => a-b); return s[Math.floor(s.length/2)]; };

  stats.count = analyses.length;
  stats.avgGoalsScored = avg(goalsScoredList);
  stats.medianGoalsScored = median(goalsScoredList);
  stats.avgGoalsConceded = avg(goalsConcededList);
  stats.avgTotalGoals = avg(totalGoalsList);
  stats.wins = resultsList.filter(r => r === 'win').length;
  stats.draws = resultsList.filter(r => r === 'draw').length;
  stats.losses = resultsList.filter(r => r === 'loss').length;
  stats.winRate = (stats.wins / stats.count * 100).toFixed(1);
  stats.drawRate = (stats.draws / stats.count * 100).toFixed(1);
  stats.lossRate = (stats.losses / stats.count * 100).toFixed(1);
  stats.over25Count = totalGoalsList.filter(g => g >= 3).length;
  stats.over25Rate = (stats.over25Count / stats.count * 100).toFixed(1);
  stats.under25Count = totalGoalsList.filter(g => g <= 2).length;
  stats.under25Rate = (stats.under25Count / stats.count * 100).toFixed(1);
  stats.bothScoredCount = bothScoredList.filter(b => b).length;
  stats.bothScoredRate = (stats.bothScoredCount / stats.count * 100).toFixed(1);
  stats.goalDistribution = {};
  for (const g of goalsScoredList) {
    const key = g >= 5 ? '5+' : String(g);
    stats.goalDistribution[key] = (stats.goalDistribution[key] || 0) + 1;
  }

  // Recent occurrences (last 10)
  const recentAnalyses = analyses.slice(-10).reverse();

  return { occurrences: analyses.length, analyses, stats, recentAnalyses };
}

// ============================================================
//  BUILT-IN PATTERNS
// ============================================================

const BUILTIN_PATTERNS = [
  {
    name: 'Low Score Reversal',
    desc: 'Scored <2 goals in 3 consecutive matches → predict goals in 4th',
    config: { metric: 'scored', compare: 'lt', value: 2, consecutive: 3, resultType: null, analysis: 'goals_scored' }
  },
  {
    name: 'Very Low Score Reversal',
    desc: 'Scored <1 goal in 3 consecutive matches → predict goals in 4th',
    config: { metric: 'scored', compare: 'lt', value: 1, consecutive: 3, resultType: null, analysis: 'goals_scored' }
  },
  {
    name: 'High Score Correction',
    desc: 'Scored ≥3 goals → predict fewer goals next match',
    config: { metric: 'scored', compare: 'gte', value: 3, consecutive: 1, resultType: null, analysis: 'goals_scored' }
  },
  {
    name: 'Clean Sheet Break',
    desc: 'Conceded 0 in 2 consecutive → predict concede next',
    config: { metric: 'conceded', compare: 'eq', value: 0, consecutive: 2, resultType: null, analysis: 'goals_conceded' }
  },
  {
    name: 'Defensive Leak',
    desc: 'Conceded ≥1 in 3 consecutive → predict concede again',
    config: { metric: 'conceded', compare: 'gte', value: 1, consecutive: 3, resultType: null, analysis: 'goals_conceded' }
  },
  {
    name: '3 Loss Streak',
    desc: 'Lost 3 consecutive → predict result in 4th',
    config: { metric: 'scored', consecutive: 3, resultType: 'loss', analysis: 'result' }
  },
  {
    name: '3 Win Streak',
    desc: 'Won 3 consecutive → predict result in 4th',
    config: { metric: 'scored', consecutive: 3, resultType: 'win', analysis: 'result' }
  },
  {
    name: 'Draw Streak Break',
    desc: 'Drew 2 consecutive → predict non-draw next',
    config: { metric: 'scored', consecutive: 2, resultType: 'draw', analysis: 'result' }
  },
  {
    name: 'High Total Goals',
    desc: 'Total goals ≥4 in 2 consecutive → predict total next',
    config: { metric: 'total', compare: 'gte', value: 4, consecutive: 2, resultType: null, analysis: 'total_goals' }
  },
  {
    name: 'Low Total Goals',
    desc: 'Total goals <2 in 2 consecutive → predict total next',
    config: { metric: 'total', compare: 'lt', value: 2, consecutive: 2, resultType: null, analysis: 'total_goals' }
  },
];

// ============================================================
//  SAVED PATTERNS (localStorage)
// ============================================================

function loadSavedPatterns() {
  try {
    return JSON.parse(localStorage.getItem('yg2_saved_patterns') || '[]');
  } catch { return []; }
}

function saveSavedPatterns(patterns) {
  localStorage.setItem('yg2_saved_patterns', JSON.stringify(patterns));
}

// ============================================================
//  UI RENDERERS
// ============================================================

let selectedTeam = null;
let currentMatches = [];

function init() {
  const sel = document.getElementById('teamSelect');
  ALL_TEAMS.sort((a, b) => a.name.localeCompare(b.name));
  for (const t of ALL_TEAMS) {
    sel.innerHTML += `<option value="${t.id}">${t.name}</option>`;
  }

  // Season selects
  const sFrom = document.getElementById('seasonFrom');
  const sTo = document.getElementById('seasonTo');
  for (const s of SEASONS) {
    sFrom.innerHTML += `<option value="${s}">${s}</option>`;
    sTo.innerHTML += `<option value="${s}">${s}</option>`;
  }
  sFrom.value = SEASONS[0];
  sTo.value = SEASONS[SEASONS.length - 1];

  // Tab switching
  document.querySelectorAll('.tab-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
      document.querySelectorAll('.tab-content').forEach(c => c.classList.remove('active'));
      btn.classList.add('active');
      document.getElementById('tab-' + btn.dataset.tab).classList.add('active');
    });
  });

  // Metric change handler
  document.getElementById('builderMetric').addEventListener('change', () => {
    const metric = document.getElementById('builderMetric').value;
    document.getElementById('builderCompareRow').style.display = metric === 'result' ? 'none' : 'flex';
    document.getElementById('builderResultRow').style.display = metric === 'result' ? 'flex' : 'none';
  });

  // Load team
  document.getElementById('btnLoadTeam').addEventListener('click', loadTeam);

  // Custom pattern
  document.getElementById('btnRunCustomPattern').addEventListener('click', runCustomPattern);
  document.getElementById('btnSaveCustomPattern').addEventListener('click', saveCustomPattern);

  // Saved patterns rendering
  renderSavedPatternsBar();

  // Match filter
  document.getElementById('matchFilter').addEventListener('change', renderMatchHistory);
}

function loadTeam() {
  const teamId = parseInt(document.getElementById('teamSelect').value);
  if (!teamId) { showToast('Please select a team', 'error'); return; }

  const team = ALL_TEAMS.find(t => t.id === teamId);
  selectedTeam = team;

  const seasonFrom = document.getElementById('seasonFrom').value;
  const seasonTo = document.getElementById('seasonTo').value;

  const allMatches = generateMatches(team.name);

  // Filter by season range
  const fromIdx = SEASONS.indexOf(seasonFrom);
  const toIdx = SEASONS.indexOf(seasonTo);
  const includedSeasons = SEASONS.slice(fromIdx, toIdx + 1);

  currentMatches = allMatches.filter(m => includedSeasons.includes(m.season));

  renderPatternResults();
  renderMatchHistory();
  document.getElementById('totalMatchesCount').textContent = currentMatches.length;

  // Switch to patterns tab
  document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
  document.querySelectorAll('.tab-content').forEach(c => c.classList.remove('active'));
  document.querySelector('[data-tab="patterns"]').classList.add('active');
  document.getElementById('tab-patterns').classList.add('active');

  showToast(`Loaded ${currentMatches.length} matches for ${team.name}`);
}

function renderPatternResults() {
  const container = document.getElementById('patternResults');
  if (!selectedTeam || currentMatches.length === 0) {
    container.innerHTML = `<div class="empty-state"><div class="big">📊</div><p>No data to analyze.</p></div>`;
    return;
  }

  let html = `<div class="team-stats">
    <div class="team-stats-header">
      <h2>${selectedTeam.name}</h2>
      <div class="meta">${currentMatches.length} matches (${document.getElementById('seasonFrom').value} – ${document.getElementById('seasonTo').value})</div>
    </div>
    <div class="match-strip">`;

  // Last 20 results
  const last20 = currentMatches.slice(-20);
  for (const m of last20) {
    const isHome = m.home === selectedTeam.name;
    const gs = isHome ? m.homeGoals : m.awayGoals;
    const gc = isHome ? m.awayGoals : m.homeGoals;
    const cls = gs > gc ? 'chip-win' : gs === gc ? 'chip-draw' : 'chip-loss';
    html += `<span class="match-chip ${cls}">${gs}-${gc}</span>`;
  }

  html += `</div></div>`;

  // Run built-in patterns
  for (const pattern of BUILTIN_PATTERNS) {
    const result = analyzePattern(currentMatches, selectedTeam.name, pattern.config);
    html += renderPatternCard(pattern.name, pattern.desc, result, pattern);
  }

  // Also run saved patterns
  const savedPatterns = loadSavedPatterns();
  for (const sp of savedPatterns) {
    const result = analyzePattern(currentMatches, selectedTeam.name, sp.config);
    if (result.stats) {
      html += renderPatternCard('💾 ' + sp.name, sp.desc, result, sp);
    }
  }

  container.innerHTML = html;
}

function renderPatternCard(name, desc, result, patternObj) {
  if (!result.stats) {
    return `<div class="results-panel">
      <h3>${name} <span class="count">— ${desc}</span></h3>
      <div style="color:var(--text2);padding:8px;font-size:0.85rem">
        Pattern never occurred in selected data (${result.occurrences} occurrences found).
      </div>
    </div>`;
  }

  const s = result.stats;
  const lastFive = result.recentAnalyses?.slice(0, 5) || [];
  const goalDist = s.goalDistribution || {};
  const maxDistCount = Math.max(...Object.values(goalDist), 1);

  let html = `<div class="results-panel">
    <h3>${name} <span class="count">— ${desc} · ${s.count} occurrences</span></h3>
    <div class="result-stat-grid">
      <div class="result-stat">
        <div class="num num-green">${s.avgGoalsScored.toFixed(2)}</div>
        <div class="lbl">Avg Goals Scored (Next)</div>
      </div>
      <div class="result-stat">
        <div class="num num-blue">${s.wins} / ${s.draws} / ${s.losses}</div>
        <div class="lbl">W / D / L</div>
      </div>
      <div class="result-stat">
        <div class="num num-gold">${s.winRate}%</div>
        <div class="lbl">Win Rate</div>
      </div>
      <div class="result-stat">
        <div class="num num-purple">${s.over25Rate}%</div>
        <div class="lbl">Over 2.5 Goals</div>
      </div>
      <div class="result-stat">
        <div class="num ${s.bothScoredRate > 50 ? 'num-green' : 'num-red'}">${s.bothScoredRate}%</div>
        <div class="lbl">Both Teams Scored</div>
      </div>
      <div class="result-stat">
        <div class="num num-gold">${s.medianGoalsScored}</div>
        <div class="lbl">Median Goals</div>
      </div>
    </div>`;

  // Goal distribution bar
  if (Object.keys(goalDist).length > 0) {
    html += `<div style="font-size:0.75rem;color:var(--text2);margin-bottom:4px">Goals distribution in next match:</div>
    <div class="distribution-bar">`;
    for (let g = 0; g <= 5; g++) {
      const key = g === 5 ? '5+' : String(g);
      const count = goalDist[key] || 0;
      const pct = (count / s.count * 100);
      if (pct > 0) {
        const colors = ['#555','#8b5cf6','#3b82f6','#22c55e','#eab308','#ef4444'];
        html += `<div class="dist-seg" style="width:${pct}%;background:${colors[g]}">${count > 2 ? g + (g===5?'+':'') : ''}</div>`;
      }
    }
    html += `</div>`;
  }

  // Recent occurrences
  if (lastFive.length > 0) {
    html += `<div style="font-size:0.75rem;color:var(--text2);margin-top:8px;margin-bottom:4px">Recent occurrences (next match result):</div>
    <table class="pattern-history-table">
      <tr><th>Date</th><th>Opponent</th><th>Score</th><th>Result</th><th>Pattern</th></tr>`;

    for (const a of lastFive) {
      const m = a.match;
      const opp = m.home === selectedTeam.name ? m.away : m.home;
      const score = m.home === selectedTeam.name ? `${m.homeGoals}-${m.awayGoals}` : `${m.awayGoals}-${m.homeGoals}`;
      const resEmoji = a.nextResult === 'win' ? '✅' : a.nextResult === 'draw' ? '➖' : '❌';
      const isHome = m.home === selectedTeam.name;
      const patternSummary = `${isHome ? 'H' : 'A'} vs ${opp}`;
      html += `<tr>
        <td style="white-space:nowrap">${m.date}</td>
        <td>${opp}</td>
        <td>${score}</td>
        <td>${resEmoji} ${a.nextResult.toUpperCase()}</td>
        <td>${patternSummary}</td>
      </tr>`;
    }
    html += `</table>`;
  }

  html += `</div>`;
  return html;
}

function runCustomPattern() {
  if (!selectedTeam || currentMatches.length === 0) {
    showToast('Please select and load a team first', 'error');
    return;
  }

  const config = getBuilderConfig();
  const result = analyzePattern(currentMatches, selectedTeam.name, config);

  document.getElementById('customPatternResults').innerHTML = renderPatternCard(
    '🔍 Custom Pattern', 
    describeConfig(config),
    result,
    config
  );
}

function describeConfig(config) {
  if (config.resultType) {
    return `${config.consecutive} consecutive ${matchLabel(config.resultType)} → analyze next match`;
  }
  return `${metricLabel(config.metric)} ${compLabel(config.compare)} ${config.value} in ${config.consecutive} consecutive → analyze next match`;
}

function metricLabel(m) {
  const labels = { scored: 'Goals Scored', conceded: 'Goals Conceded', total: 'Total Goals', margin: 'Goal Margin', result: 'Result' };
  return labels[m] || m;
}
function compLabel(c) {
  const labels = { lt: '<', lte: '≤', eq: '=', gte: '≥', gt: '>' };
  return labels[c] || c;
}
function matchLabel(r) {
  const labels = { win: 'wins', draw: 'draws', loss: 'losses', not_loss: 'not-lost', not_win: 'not-won' };
  return labels[r] || r;
}

function getBuilderConfig() {
  const metric = document.getElementById('builderMetric').value;
  const compare = document.getElementById('builderCompare').value;
  const value = parseInt(document.getElementById('builderValue').value) || 1;
  const consecutive = parseInt(document.getElementById('builderConsecutive').value) || 3;
  const resultType = metric === 'result' ? document.getElementById('builderResult').value : null;
  const analysis = document.getElementById('builderAnalysis').value;

  return { metric, compare, value, consecutive, resultType, analysis };
}

function saveCustomPattern() {
  const name = prompt('Name your pattern:');
  if (!name) return;

  const saved = loadSavedPatterns();
  const config = getBuilderConfig();
  const desc = describeConfig(config);

  saved.push({
    id: Date.now(),
    name,
    desc,
    config,
    created: new Date().toISOString()
  });

  saveSavedPatterns(saved);
  renderSavedPatternsBar();
  showToast(`Pattern "${name}" saved!`);
}

function renderSavedPatternsBar() {
  const saved = loadSavedPatterns();
  const bar = document.getElementById('savedPatternsBar');

  if (saved.length === 0) {
    bar.innerHTML = '';
    return;
  }

  let html = '<div class="saved-patterns">';
  for (const sp of saved) {
    html += `<div class="saved-pattern-pill" onclick="runSavedPattern(${sp.id})" title="${sp.desc}">
      ${sp.name} <span class="remove" onclick="event.stopPropagation();deleteSavedPattern(${sp.id})">×</span>
    </div>`;
  }
  html += '</div>';
  bar.innerHTML = html;

  // Render saved tab
  const list = document.getElementById('savedPatternList');
  if (saved.length === 0) {
    list.innerHTML = `<div class="empty-state"><div class="big">📋</div><p>No saved patterns yet.</p></div>`;
    return;
  }

  let lhtml = '';
  for (const sp of saved) {
    lhtml += `<div class="results-panel" style="cursor:pointer" onclick="runSavedPattern(${sp.id})">
      <div style="display:flex;justify-content:space-between;align-items:center">
        <div>
          <h3>💾 ${sp.name}</h3>
          <div style="font-size:0.8rem;color:var(--text2)">${sp.desc}</div>
        </div>
        <div>
          <button class="btn-secondary btn-sm" onclick="event.stopPropagation();deleteSavedPattern(${sp.id})">Delete</button>
        </div>
      </div>
    </div>`;
  }
  list.innerHTML = lhtml;
}

function runSavedPattern(id) {
  const saved = loadSavedPatterns();
  const sp = saved.find(p => p.id === id);
  if (!sp) return;

  if (!selectedTeam || currentMatches.length === 0) {
    showToast('Select and load a team first', 'error');
    return;
  }

  const result = analyzePattern(currentMatches, selectedTeam.name, sp.config);

  // Show in analysis tab
  const container = document.getElementById('patternResults');
  let html = `<div class="team-stats"><div class="team-stats-header"><h2>${selectedTeam.name} — ${sp.name}</h2><div class="meta">${sp.desc}</div></div></div>`;
  html += renderPatternCard('💾 ' + sp.name, sp.desc, result, sp.config);
  container.innerHTML = html;

  // Switch to patterns tab
  document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
  document.querySelectorAll('.tab-content').forEach(c => c.classList.remove('active'));
  document.querySelector('[data-tab="patterns"]').classList.add('active');
  document.getElementById('tab-patterns').classList.add('active');

  showToast(`Pattern "${sp.name}" applied to ${selectedTeam.name}`);
}

function deleteSavedPattern(id) {
  let saved = loadSavedPatterns();
  saved = saved.filter(p => p.id !== id);
  saveSavedPatterns(saved);
  renderSavedPatternsBar();
  showToast('Pattern deleted');
}

function renderMatchHistory() {
  const container = document.getElementById('matchHistoryList');
  if (!selectedTeam || currentMatches.length === 0) {
    return;
  }

  let filtered = [...currentMatches];
  const filter = document.getElementById('matchFilter').value;

  switch (filter) {
    case 'home': filtered = filtered.filter(m => m.home === selectedTeam.name); break;
    case 'away': filtered = filtered.filter(m => m.away === selectedTeam.name); break;
    case 'wins': filtered = filtered.filter(m => {
      return m.home === selectedTeam.name ? m.homeGoals > m.awayGoals : m.awayGoals > m.homeGoals;
    }); break;
    case 'losses': filtered = filtered.filter(m => {
      return m.home === selectedTeam.name ? m.homeGoals < m.awayGoals : m.awayGoals < m.homeGoals;
    }); break;
    case 'draws': filtered = filtered.filter(m => m.homeGoals === m.awayGoals); break;
    case 'over25': filtered = filtered.filter(m => (m.homeGoals + m.awayGoals) >= 3); break;
    case 'under25': filtered = filtered.filter(m => (m.homeGoals + m.awayGoals) <= 2); break;
  }

  if (filtered.length === 0) {
    container.innerHTML = '<div class="empty-state"><p>No matches match this filter.</p></div>';
    return;
  }

  // Show last 200 matches
  const display = filtered.slice(-200).reverse();
  let html = '<div class="match-list">';
  for (const m of display) {
    const isHome = m.home === selectedTeam.name;
    const opp = isHome ? m.away : m.home;
    const gs = isHome ? m.homeGoals : m.awayGoals;
    const gc = isHome ? m.awayGoals : m.homeGoals;
    const score = `${gs} - ${gc}`;
    const result = gs > gc ? '✅' : gs === gc ? '➖' : '❌';
    html += `<div class="match-row">
      <div>
        <span class="season">${m.season}</span>
        <span class="teams">${isHome ? '🏠' : '✈️'} ${selectedTeam.name} vs ${opp}</span>
      </div>
      <div>
        <span class="score">${result} ${score}</span>
      </div>
    </div>`;
  }
  html += '</div>';
  container.innerHTML = html;
}

// ============================================================
//  TOAST
// ============================================================
function showToast(msg, type = 'success') {
  const t = document.getElementById('toast');
  t.textContent = msg;
  t.className = 'toast show ' + type;
  clearTimeout(t._timer);
  t._timer = setTimeout(() => t.classList.remove('show'), 2500);
}

// ============================================================
//  INIT
// ============================================================
init();
</script>
